class UnderstandingModal extends FuzzySuggestModal<UnderstandingOption> {
  constructor(
    app: App,
    private editor: Editor,
    private selected: string,
    private tag: TagOption,
    private plugin: CanvasLearningPlugin,
  ) {
    super(app);
    this.setPlaceholder(`第 2/2 步：选理解度（Tag: ${tag.label}）`);
  }

  getItems(): UnderstandingOption[] {
    return [...UNDERSTANDING_OPTIONS];
  }

  getItemText(item: UnderstandingOption): string {
    return item.label;
  }

  onChooseItem(und: UnderstandingOption) {
    // 1) 本地写入 callout
    const from = this.editor.getCursor("from");
    const wrapped = wrapSelection(this.selected, this.tag, und.value);
    this.editor.replaceSelection(wrapped);

    // 2) P0-6 (2026-05-14): 光标自动定位到 callout 末尾用户输入区
    // wrapped 最后一行是 "> "（USER_INPUT_PROMPT），光标停在 ch=2 让用户直接输入。
    // 这样用户做完 tag + understanding 选择后，自然继续打字写下自己的理解 / 疑问 /
    // 批注，无需额外 modal，符合 Obsidian native UX。
    const wrappedLines = wrapped.split("\n");
    const targetLine = from.line + wrappedLines.length - 1;
    const targetCh = USER_INPUT_PROMPT.length; // "> " 后面
    this.editor.setCursor({ line: targetLine, ch: targetCh });
    this.editor.focus();

    // 3) P0-1 (2026-05-13) DEPRECATED 2026-05-14 路径 1 决策:
    // Plan B 数据入口已禁用 — 不再 POST /api/v1/tips。
    // Plan A 改由 FrontmatterTipsSync 监听 vault.on('modify') 写 frontmatter
    // tips[] 直接到本地 .md, 无 backend call. 见 plan-b-postmortem.md
    //
    // void this.plugin.saveCalloutToBackend(
    //   this.selected, this.tag, und.value as UnderstandingValue,
    // );
  }
}

/**
 * MVP-α-3 (2026-05-14) — Quick Exam markdown UI.
 *
 * 用户体验 (来自 _bmad-output/research/2026-05-14-mvp-alpha-parallel-dev-plan.md §1):
 *   T=4:00 Dashboard 点 "🎯 一键考察"
 *     → 反馈瞬间 #4: 后端 5s 内生成 1 道题, 引用用户批注原话
 *     → plugin 把题目写成 canvas-vault/节点/考察-{concept}-{date}.md
 *     → workspace.openLinkText 打开
 *   T=6:00 用户手写答案
 *   T=8:00 Cmd+S 保存
 *     → 反馈瞬间 #5: vault.on('modify') 监听 → POST /grade → 文件底部追加反馈
 *
 * Backend 接口 (协调文档 §5 锁定):
 *   POST /api/v1/exam/quick  body: {node_id, vault_id?}   resp: {question_id, question_text, generated_at?}
 *   POST /api/v1/exam/grade  body: {question_id, user_answer}  resp: {score, feedback, mastery_delta?}
 *
 * 设计:
 *   - 同 status-bar.ts: pure functions + thin Controller, 后者 wiring 在 main.ts
 *   - 答题文件在 节点/ 下 (spec 要求) — 用日期 + 重名递增 -1/-2 避免覆盖
 *   - vault.on('modify') 仅对已注册的考察文件 (Map<path, session>) 触发评分
 *   - "已评分" flag 防重复 grade (用户多次 Cmd+S 不应反复打分)
 *   - 静默失败回退 Notice 文案 (callBackend 已有失败 Notice, 不重复触发)
 */

import type { App, TFile, Vault } from "obsidian";

// ─────────────────────────────────────────────────────────────
// Pure functions (testable)
// ─────────────────────────────────────────────────────────────

/**
 * 构造考察文件路径.
 *
 *   buildExamFilePath("递归", "2026-05-14")         → "节点/考察-递归-2026-05-14.md"
 *   buildExamFilePath("递归", "2026-05-14", 1)      → "节点/考察-递归-2026-05-14-1.md"
 *
 * concept 内空白被替换成 - 防 wikilink 解析歧义.
 */
export function buildExamFilePath(
  concept: string,
  date: string,
  suffix?: number,
): string {
  const safeConcept = (concept || "unknown").trim().replace(/\s+/g, "-");
  const safeDate = (date || "").trim();
  const tail = suffix !== undefined && suffix > 0 ? `-${suffix}` : "";
  return `节点/考察-${safeConcept}-${safeDate}${tail}.md`;
}

/** 今日 YYYY-MM-DD (UTC+8 简化版 — 用 ISO date 取前 10 字符). */
export function todayDateStr(now: Date = new Date()): string {
  return now.toISOString().slice(0, 10);
}

/**
 * 构造考察文件 markdown body.
 *
 * 协议 (来自用户 prompt):
 *   # 考察: {concept}
 *   ## 题目
 *   {question_text}
 *   ## 你的回答
 *   [在此填写]
 *   ## 提交 (Cmd+S 自动触发评分)
 *
 * frontmatter 写入 question_id + source_concept, 让 vault.on('modify') 回调能从
 * 文件本身回查 backend session, 不依赖 in-memory map (插件 reload 后仍可继续答题).
 */
export function buildExamFileBody(input: {
  concept: string;
  questionId: string;
  questionText: string;
  generatedAt?: string;
}): string {
  const lines: string[] = [
    "---",
    `exam_question_id: ${input.questionId}`,
    `source_concept: ${input.concept}`,
    `generated_at: ${input.generatedAt ?? new Date().toISOString()}`,
    "exam_status: pending",
    "---",
    "",
    `# 考察: ${input.concept}`,
    "",
    "## 题目",
    "",
    input.questionText.trim(),
    "",
    "## 你的回答",
    "",
    "[在此填写]",
    "",
    "## 提交 (Cmd+S 自动触发评分)",
    "",
    "保存文件即自动调用后端评分, 评分结果会追加到文件底部 ## 反馈 段.",
    "",
  ];
  return lines.join("\n");
}

/**
 * 提取 "## 你的回答" 段的内容.
 *
 * - 起点: "## 你的回答" 之后第一行
 * - 终点: 下一个 "## " 标题 (不含) / 文件末尾
 * - 去掉占位符 "[在此填写]" — 如果用户没改这个文本, 视作未作答返回 null
 * - 去除前后空行后, 内容为空 → 返回 null (调用方判断是否触发 grade)
 */
export function extractAnswer(content: string): string | null {
  const lines = content.split("\n");
  const start = lines.findIndex((l) => l.trim().startsWith("## 你的回答"));
  if (start === -1) return null;

  const body: string[] = [];
  for (let i = start + 1; i < lines.length; i++) {
    const line = lines[i];
    if (line.trim().startsWith("## ")) break;
    body.push(line);
  }

  const text = body.join("\n").trim();
  if (!text) return null;
  if (text === "[在此填写]") return null;
  // 用户保留占位符但加了内容 — 把占位符行剔除
  const cleaned = body
    .filter((l) => l.trim() !== "[在此填写]")
    .join("\n")
    .trim();
  return cleaned || null;
}

/**
 * 判断文件是否已经追加过 "## 反馈" 段 (防重复 grade).
 *
 * 注意: 中文字符在 JS regex 不算 \w, "反馈" 后的 \b 永远不匹配 → 不能用 \b
 * 把"## 反馈" 跟段标题锚定的责任交给 `^##\s*` 部分 (行首 + 两个 #),
 * 普通文本里的 "反馈" 不会以 ## 开头, 所以无需额外 word-boundary.
 */
export function hasFeedbackSection(content: string): boolean {
  return /^##\s*反馈/m.test(content);
}

/**
 * 构造追加到文件末尾的反馈区文本.
 *
 *   ## 反馈 (4/5)
 *
 *   你说对了核心,但 base case 写法可以更紧凑...
 *
 * 前置 \n\n 保证跟前文段隔行, 末尾 \n 让追加多次仍有换行.
 */
export function buildFeedbackAppend(input: {
  score: number;
  feedback: string;
}): string {
  const safeScore = Math.max(0, Math.min(5, Math.round(input.score)));
  const text = (input.feedback ?? "").trim() || "(后端未返回文字反馈)";
  return `\n\n## 反馈 (${safeScore}/5)\n\n${text}\n`;
}

// ─────────────────────────────────────────────────────────────
// Controller (thin wiring, depends on Obsidian runtime)
// ─────────────────────────────────────────────────────────────

/**
 * QuickExamController 需要的最小 plugin 接口.
 *
 * - app: Obsidian app (vault / workspace / metadataCache)
 * - callBackendJson: 发 backend 请求并返回 JSON (失败已自动 Notice, 失败时返回 null)
 * - inferVaultId: 当前 vault_id (用于 backend session 路由)
 */
export interface QuickExamPluginAPI {
  app: App;
  callBackendJson(
    endpoint: string,
    label: string,
    body: Record<string, unknown>,
    method?: "GET" | "POST",
  ): Promise<unknown | null>;
  inferCurrentVaultId(): string;
}

interface ExamSession {
  questionId: string;
  concept: string;
  filePath: string;
  graded: boolean;
}

export class QuickExamController {
  private sessions = new Map<string, ExamSession>();

  constructor(private plugin: QuickExamPluginAPI) {}

  /**
   * 命令面板入口 "canvas:start-quick-exam".
   *
   * 流程:
   *   1. active file 必须在 节点/ 下 → 取 basename 作为 concept
   *   2. Notice "🤔 正在生成题目..." (反馈瞬间 #4 开端)
   *   3. POST /api/v1/exam/quick → 拿 question_text
   *   4. 生成 节点/考察-{concept}-{date}.md (含 frontmatter exam_question_id)
   *   5. workspace.openLinkText 打开新文件 (新 tab)
   *   6. 注册 session 让 onFileModified 能识别这个文件
   *   7. Notice "📄 题目已生成"
   */
  async startExam(NoticeCtor: typeof import("obsidian").Notice): Promise<void> {
    const active = this.plugin.app.workspace.getActiveFile();
    if (!active) {
      new NoticeCtor("请先打开你想考察的节点 (节点/<concept>.md)", 5000);
      return;
    }
    if (!active.path.startsWith("节点/") || active.basename.startsWith("考察-")) {
      new NoticeCtor(
        "考察命令需在 节点/<concept>.md 上触发 (不要在考察文件本身或其他目录)",
        5000,
      );
      return;
    }

    const concept = active.basename;
    new NoticeCtor("🤔 正在生成题目...", 3000);

    const resp = await this.plugin.callBackendJson(
      "/api/v1/exam/quick",
      `生成 "${concept}" 的考察题`,
      {
        node_id: concept,
        vault_id: this.plugin.inferCurrentVaultId(),
      },
      "POST",
    );
    if (!resp) return; // callBackendJson 已发失败 Notice
    const r = resp as {
      question_id?: string;
      question_text?: string;
      generated_at?: string;
    };
    if (!r.question_id || !r.question_text) {
      new NoticeCtor(
        "后端返回数据缺 question_id / question_text — 接口契约未对齐",
        6000,
      );
      return;
    }

    const filePath = await this.resolveUniquePath(concept);
    const body = buildExamFileBody({
      concept,
      questionId: r.question_id,
      questionText: r.question_text,
      generatedAt: r.generated_at,
    });
    let file: TFile;
    try {
      file = await this.plugin.app.vault.create(filePath, body);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      new NoticeCtor(`❌ 创建考察文件失败: ${msg}`, 6000);
      return;
    }

    this.sessions.set(file.path, {
      questionId: r.question_id,
      concept,
      filePath: file.path,
      graded: false,
    });

    await this.plugin.app.workspace.openLinkText(file.path, "", true);
    new NoticeCtor(`📄 题目已生成: ${file.basename}`, 4000);
  }

  /**
   * vault.on('modify') 回调.
   *
   * 仅当 file 在已注册 sessions 内且未评分时触发评分.
   * 评分成功后 graded=true, 用户继续编辑同文件不会反复 grade.
   *
   * 注意: 本方法被 Obsidian 高频触发 (用户每次按键 / autosave 都打), 必须先 fast
   * filter 排除非考察文件. 实际网络调用在 grade flag 守门后.
   */
  async onFileModified(
    file: TFile,
    NoticeCtor: typeof import("obsidian").Notice,
  ): Promise<void> {
    const session = this.sessions.get(file.path);
    if (!session || session.graded) return;

    const content = await this.plugin.app.vault.read(file);
    if (hasFeedbackSection(content)) {
      // 反馈已写但 session 标记仍 pending — 强制标 graded 防再次进入
      session.graded = true;
      return;
    }
    const answer = extractAnswer(content);
    if (!answer) return; // 用户还没填写

    // 防并发 grade (两次快速保存) — 提前标记
    session.graded = true;

    new NoticeCtor("⏳ 正在评分...", 3000);
    const resp = await this.plugin.callBackendJson(
      "/api/v1/exam/grade",
      `评分 "${session.concept}"`,
      {
        question_id: session.questionId,
        user_answer: answer,
      },
      "POST",
    );
    if (!resp) {
      // backend 调用失败 → 放回 ungraded 让用户改答案后再试
      session.graded = false;
      return;
    }
    const r = resp as { score?: number; feedback?: string };
    if (r.score === undefined || r.feedback === undefined) {
      session.graded = false;
      new NoticeCtor(
        "后端返回数据缺 score / feedback — 接口契约未对齐",
        6000,
      );
      return;
    }

    const appendText = buildFeedbackAppend({
      score: r.score,
      feedback: r.feedback,
    });
    // Obsidian 没有 vault.append, 用 process(file, fn) atomic read-modify-write.
    // process 会自动 dedupe 并发修改, 比 read+modify 安全.
    await this.plugin.app.vault.process(file, (current) => current + appendText);
    new NoticeCtor(`✅ 评分完成: ${r.score}/5`, 5000);
  }

  /**
   * 找一个不重名的 节点/考察-{concept}-{date}.md 路径.
   *
   * - 首选 suffix=undefined → "节点/考察-X-2026-05-14.md"
   * - 已存在则 -1, -2, -3... 上限 99 防爆
   */
  private async resolveUniquePath(concept: string): Promise<string> {
    const date = todayDateStr();
    const exists = (p: string) =>
      this.plugin.app.vault.getAbstractFileByPath(p) !== null;

    const primary = buildExamFilePath(concept, date);
    if (!exists(primary)) return primary;

    for (let n = 1; n < 100; n++) {
      const p = buildExamFilePath(concept, date, n);
      if (!exists(p)) return p;
    }
    // 极端情况: 一天里同一节点考察 100 次 — fallback timestamp
    return buildExamFilePath(concept, date, Date.now());
  }
}

/**
 * Vault append 兜底 — 老版本 Obsidian 没 vault.append, 这里 inline shim.
 *
 * 不导出, controller 通过 plugin.app.vault.append 调用 — modern Obsidian (1.0+)
 * 都支持. 若 build target 触及更老版本, 在 main.ts 用 vault.read + vault.modify
 * 重新实现.
 */
export type { Vault };

/**
 * MVP-α-5 (2026-05-14) — Plugin 反馈 toast + 状态栏.
 *
 * 用户初衷 (来自 _bmad-output/research/2026-05-14-mvp-alpha-parallel-dev-plan.md §1):
 *   用户 10 分钟体验 MVP-α 时需要 5 个反馈瞬间, 让 "AI 看到我做的" 这件事可感.
 *   本模块负责其中的 2 个非 backend-dependent 瞬间:
 *     · 瞬间 #2 — Tips 数自增 (status bar 数字跃迁 + 短 Notice)
 *     · 瞬间 #3 — 导航路径 (status bar 显示 "递归 → factorial")
 *
 * 真相源 (复用 Story 2.4 Plan A):
 *   FrontmatterTipsSync 已经把 callout 同步到 frontmatter.tips[] 数组,
 *   本模块直接读 metadataCache.getFileCache(file).frontmatter.tips 长度,
 *   不再重新 parse callout — 单一数据流, 无重复.
 *
 * 设计原则 (复用 vault-indicator.ts 模式):
 *   - pure functions 不依赖 Obsidian runtime, node:test 可直接 import
 *   - StatusBarController 类持有 plugin + HTMLElement, 仅在 main.ts 实例化
 *   - Notice 触发用 callback 注入 (避免本模块顶部 import Notice 拖入 Obsidian
 *     runtime 到 test bundle, 跟 vault-indicator 一样保持纯净)
 */

import type { App, TFile } from "obsidian";

// ─────────────────────────────────────────────────────────────
// Pure functions (testable, no Obsidian runtime)
// ─────────────────────────────────────────────────────────────

/**
 * 从 frontmatter 提取 tips[] 数量.
 *
 * Story 2.4 FrontmatterTipsSync 写入约定:
 *   - 有 callout: fm.tips = FrontmatterTip[] (数组)
 *   - 无 callout: fm.tips 字段被 delete
 *
 * 防御性: 字段缺失 / 类型异常 (非数组) → 返回 0.
 */
export function countTipsFromFrontmatter(
  fm: Record<string, unknown> | null | undefined,
): number {
  if (!fm) return 0;
  const tips = fm.tips;
  if (!Array.isArray(tips)) return 0;
  return tips.length;
}

/**
 * 构造导航路径文字 "递归 → factorial".
 *
 * - prev 为空 (第一次打开) → 只返回 current
 * - prev === current (重复打开同一文件) → 只返回 current, 不冗余箭头
 * - 两端 trim, 防 frontmatter 误注空白
 * - current 为空 → 返回 "" (调用方决定如何兜底)
 */
export function buildNavPath(
  current: string,
  prev?: string | null,
): string {
  const cur = (current ?? "").trim();
  if (!cur) return "";
  const p = (prev ?? "").trim();
  if (!p || p === cur) return cur;
  return `${p} → ${cur}`;
}

/**
 * 构造 status bar 文本 (Tips 计数 + 导航路径).
 *
 * 格式:
 *   - 有 navPath: "📝 Tips: 2 · 📍 递归 → factorial"
 *   - 无 navPath: "📝 Tips: 0"
 *
 * 设计:
 *   - tips 段始终显示 (即使 N=0, 让用户看到从 0 → 1 的跃迁)
 *   - " · " 分隔, 风格与 vault-indicator.buildStatusBarLabel 一致
 *   - emoji 前缀让 status bar 即使被其他插件挤压也能瞥见
 */
export function buildStatusBarText(input: {
  tipsCount: number;
  navPath: string;
}): string {
  const tipsSeg = `📝 Tips: ${input.tipsCount}`;
  const pathSeg = input.navPath ? `📍 ${input.navPath}` : "";
  return pathSeg ? `${tipsSeg} · ${pathSeg}` : tipsSeg;
}

/**
 * 判断 tips 计数变化方向, 用于决定是否触发 Notice 反馈瞬间.
 *
 *   - "init":     prev === undefined (首次填充) → 不触发, 避免初始化噪音
 *   - "increase": new > prev → 用户新写了 callout → 触发 Notice "🎓 已记住 N 条"
 *   - "decrease": new < prev → 用户删了 callout → 不触发 (静默, 避免负面感觉)
 *   - "same":     不变 → 不触发
 */
export type TipsCountTransition = "init" | "increase" | "decrease" | "same";

export function classifyTipsTransition(
  prev: number | undefined,
  next: number,
): TipsCountTransition {
  if (prev === undefined) return "init";
  if (next > prev) return "increase";
  if (next < prev) return "decrease";
  return "same";
}

/**
 * 路径是否在 status bar 的 nav path 追踪范围 (节点/ 或 原白板/).
 *
 * 其他文件 (Dashboard.md / templates/ / 验收单/ / raw/) 不入 path —
 * 用户切到 Dashboard 后再切回学习节点, status bar 应继续显示学习路径,
 * 不要让 Dashboard 这种功能性文件污染 "递归 → factorial" 故事感.
 */
export function shouldTrackInNavPath(path: string): boolean {
  return path.startsWith("节点/") || path.startsWith("原白板/");
}

/**
 * 构造 Tips 自增 Notice 文案.
 *
 * pure function 单独 export 让 main.ts wiring 和测试用同一份文案,
 * 避免 hard-coded 字符串在两处分叉.
 */
export function buildTipsIncreaseNotice(count: number): string {
  return `🎓 已记住 ${count} 条 Tips`;
}

// ─────────────────────────────────────────────────────────────
// StatusBarController (thin wiring, depends on Obsidian runtime)
// ─────────────────────────────────────────────────────────────

/**
 * 主 plugin 暴露给 StatusBarController 用的最小接口.
 *
 * 用 structural interface 而非 import CanvasLearningPlugin 避免 cycle:
 *   main.ts → status-bar.ts → main.ts 会让 esbuild 抱怨。
 */
export interface StatusBarPluginAPI {
  app: App;
}

/**
 * StatusBarController — 持有 HTMLElement, 维护 tips 计数 + 导航路径状态.
 *
 * 由 main.ts onload 实例化:
 *
 *   const el = this.addStatusBarItem();
 *   this.statusBar = new StatusBarController(this, el, {
 *     onTipsIncreased: (count) => new Notice(buildTipsIncreaseNotice(count), 2500),
 *   });
 *   this.registerEvent(
 *     this.app.metadataCache.on('changed', (f) => this.statusBar.handleMetadataChanged(f as TFile))
 *   );
 *   this.registerEvent(
 *     this.app.workspace.on('file-open', (f) => this.statusBar.handleFileOpen(f))
 *   );
 *
 * 设计:
 *   - 不直接 registerEvent (DI 让 main.ts 注册) — 关注点分离 + 单测容易 mock
 *   - 持有 currentFile + prevFile + lastTipsCount 三态
 *   - render() 仅 element.setText, 不重建 DOM
 *   - Notice 触发用 onTipsIncreased 回调注入 (不在本模块顶部 import Notice)
 */
export class StatusBarController {
  private currentFile: TFile | null = null;
  private prevFile: TFile | null = null;
  private lastTipsCount: number | undefined = undefined;

  constructor(
    private plugin: StatusBarPluginAPI,
    private element: HTMLElement,
    private opts: {
      onTipsIncreased?: (count: number) => void;
    } = {},
  ) {
    this.render();
  }

  /**
   * metadataCache.on('changed') 触发: file frontmatter 已重新解析.
   *
   * 仅当此 file 是当前 active file 时更新 (避免后台 sync 噪音).
   * 计数 increase 时触发 onTipsIncreased 回调 (Notice 反馈瞬间 #2).
   */
  handleMetadataChanged(file: TFile): void {
    if (!this.currentFile || file.path !== this.currentFile.path) return;
    const count = this.readTipsCount(file);
    const transition = classifyTipsTransition(this.lastTipsCount, count);
    this.lastTipsCount = count;
    this.render();
    if (transition === "increase" && this.opts.onTipsIncreased) {
      this.opts.onTipsIncreased(count);
    }
  }

  /**
   * workspace.on('file-open') 触发: 更新 prev → current.
   *
   * - file 为 null (用户关闭所有文件) → 清空 currentFile, 保留 prev (历史路径)
   * - 不在 shouldTrackInNavPath 范围 → 不更新 (Dashboard 等不污染 path)
   * - 重复打开同一文件 → 不更新 prev (避免 "factorial → factorial")
   */
  handleFileOpen(file: TFile | null): void {
    if (!file) {
      this.currentFile = null;
      this.lastTipsCount = undefined;
      this.render();
      return;
    }
    if (!shouldTrackInNavPath(file.path)) {
      return;
    }
    if (this.currentFile && this.currentFile.path !== file.path) {
      this.prevFile = this.currentFile;
    }
    this.currentFile = file;
    this.lastTipsCount = this.readTipsCount(file);
    this.render();
  }

  /**
   * 暴露给 main.ts 在 backend 阶段切换时手动追加 status bar 提示 (α-3 用).
   *
   * 比如 "正在生成题目..." / "评分完成" 阶段, main.ts 可调
   * statusBar.setTransientHint("⏳ 出题中") 让用户瞥见阶段, render() 再把它清掉.
   *
   * 当前留 stub, α-3 落地时再补 lifecycle (timer / explicit clear).
   */
  setTransientHint(_hint: string | null): void {
    // α-3 落地时 wire up
  }

  // ─── private ───

  private readTipsCount(file: TFile): number {
    const fm = this.plugin.app.metadataCache.getFileCache(file)?.frontmatter;
    return countTipsFromFrontmatter(fm);
  }

  private render(): void {
    const navPath = this.currentFile
      ? buildNavPath(this.currentFile.basename, this.prevFile?.basename)
      : "";
    const text = buildStatusBarText({
      tipsCount: this.lastTipsCount ?? 0,
      navPath,
    });
    this.element.setText(text);
  }
}

export const TAG_OPTIONS = [
  { value: "tips", label: "💡 Tips", callout: "tips" },
  { value: "error", label: "❌ 错误", callout: "error" },
  { value: "question", label: "❓ 提问", callout: "question" },
  { value: "keypoint", label: "📌 关键点", callout: "keypoint" },
] as const;

export type TagOption = (typeof TAG_OPTIONS)[number];
export type TagValue = TagOption["value"];

export const UNDERSTANDING_OPTIONS = [
  { value: "understood", label: "✅ 已懂" },
  { value: "fuzzy", label: "🤔 模糊" },
  { value: "not-understood", label: "❌ 不懂" },
] as const;

export type UnderstandingOption = (typeof UNDERSTANDING_OPTIONS)[number];
export type UnderstandingValue = UnderstandingOption["value"];

/**
 * P0-6 (2026-05-14): callout 末尾追加一个空 "> " 行作为用户输入区。
 * UnderstandingModal.onChooseItem 会在 replaceSelection 后把光标停在这一行，
 * 让用户能直接继续输入自己对原文的理解 / 疑问 / 批注。
 *
 * 输出格式：
 *   > [!tips]+ 💡 Tips
 *   > - [ ] ✅ 已懂
 *   > - [x] 🤔 模糊
 *   > - [ ] ❌ 不懂
 *   >
 *   > {选中的原文}
 *   >
 *   > {光标停这里 ← 用户继续输入}
 */
// F1 (2026-05-14): v1 用空 "> " 但 Obsidian Live Preview 把纯空 callout 行
// 渲染为 0 高度结构装饰，用户看不到光标。v2 改成 visible 占位符 — Live Preview
// 必须渲染（含可见字符），占位符本身是 prompt 提示。
// 见 forum.obsidian.md/t/88607 + 5-14 4-agent 调研报告。
export const USER_INPUT_PROMPT = "> ✍️ 我的理解：";

// ═══════════════════════════════════════════════════════════════════════════════
// Story 2.4 Plan B Phase 1 (2026-05-14): Callout Parser + SHA256 dedup hash
//
// 用于 CalloutSyncDebouncer：监听 vault.on('modify') 后解析文件全部 callout，
// 用 content_hash 跟 backend 做幂等同步（同 hash 跳过，不同 hash 创建 v2 episode）。
// ═══════════════════════════════════════════════════════════════════════════════

export interface ParsedCallout {
  tag: string; // tips / error / question / keypoint
  tagLabel: string; // "💡 Tips" 等
  understanding: string; // understood / fuzzy / not-understood / ""
  content: string; // callout body（含用户输入的"我的理解"），已去掉 checkbox 行
  contentHash: string; // SHA256(node_id|tag|understanding|content)
}

/**
 * 从文件内容提取所有 [!tag]+ callout（4 种类型：tips/error/question/keypoint）。
 *
 * 跳过：
 *   - 非 4-tag callout（如 [!tip] 单数 / [!note] / [!warning]）
 *   - 空 callout（无 body 内容）
 *
 * 返回：ParsedCallout[] — 包含 content_hash 用于 backend 幂等去重
 */
export async function parseCalloutsFromContent(
  content: string,
  nodeId: string,
): Promise<ParsedCallout[]> {
  const callouts: ParsedCallout[] = [];
  const lines = content.split("\n");
  let i = 0;

  while (i < lines.length) {
    // Plan A v2 (2026-05-14): 严格协议 — 4 路 agent 对抗审查共识
    //
    // 双 telltale 防误识别:
    //   1. 仅 4 种复数 tag (tips/error/question/keypoint) — 对齐 plugin UI
    //      TAG_OPTIONS (line 2-7), 排除 [!tip] 单数 (Story 1.16 4-tag 决策更新版)
    //   2. +/- 后缀必填 — Story 2.4 spec AC#3 折叠/展开两态都要识别,
    //      模板 [!tip] 💬 (node-derivation.ts:218 自动生成) 无后缀, 双不匹配排除
    //
    // 协议规约 (用户 callout vs 模板 hint):
    //   - 用户 Cmd+Shift+A 写: [!tips]+ / [!error]+ / [!question]+ / [!keypoint]+
    //   - 模板/AI 自动写: [!tip] (单数无后缀) / [!quote]+ / [!relation/*]+ / [!info]+ 等
    //   - 4 个复数 tag 是 "用户保留" 命名空间, 模板不准用
    //
    // 见 _bmad-output/research/2026-05-14-plan-b-postmortem.md
    const headerMatch = lines[i].match(
      /^>\s*\[!(tips|error|question|keypoint)\][+-]\s*(.*)$/i,
    );
    if (!headerMatch) {
      i++;
      continue;
    }
    const tag = headerMatch[1].toLowerCase();
    const tagLabel = headerMatch[2].trim();

    // 收集后续连续 `>` 开头的行作为 callout body
    const bodyLines: string[] = [];
    i++;
    while (i < lines.length && lines[i].startsWith(">")) {
      bodyLines.push(lines[i].replace(/^>\s?/, ""));
      i++;
    }

    // 从 body 提取 understanding（首个 [x] checkbox）
    let understanding = "";
    for (const bl of bodyLines) {
      const cbMatch = bl.match(/^-\s*\[x\]\s*(.*)$/);
      if (cbMatch) {
        const label = cbMatch[1];
        if (label.includes("已懂")) understanding = "understood";
        else if (label.includes("模糊")) understanding = "fuzzy";
        else if (label.includes("不懂")) understanding = "not-understood";
        break;
      }
    }

    // content = 去掉所有 checkbox 行 + 空行后剩余文本
    const contentLines = bodyLines.filter(
      (bl) => !bl.match(/^-\s*\[[ x]\]/) && bl.trim() !== "",
    );
    const calloutContent = contentLines.join("\n").trim();
    if (!calloutContent) continue; // 空 callout 跳过

    const hash = await sha256Hex(
      `${nodeId}|${tag}|${understanding}|${calloutContent}`,
    );
    callouts.push({
      tag,
      tagLabel,
      understanding,
      content: calloutContent,
      contentHash: hash,
    });
  }

  return callouts;
}

async function sha256Hex(text: string): Promise<string> {
  const enc = new TextEncoder();
  const buf = await crypto.subtle.digest("SHA-256", enc.encode(text));
  return Array.from(new Uint8Array(buf))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

export function wrapSelection(
  text: string,
  tag: TagOption,
  understanding: UnderstandingValue,
): string {
  const header = `> [!${tag.callout}]+ ${tag.label}`;
  const checkboxes = UNDERSTANDING_OPTIONS.map(
    (opt) => `> - [${opt.value === understanding ? "x" : " "}] ${opt.label}`,
  ).join("\n");
  const body = text
    .split("\n")
    .map((line) => `> ${line}`)
    .join("\n");
  // 末尾结构：[原文] → 空 ">" 分隔行 → "> " 用户输入区（带尾随空格，光标停这里）
  return `${header}\n${checkboxes}\n>\n${body}\n>\n${USER_INPUT_PROMPT}`;
}

export interface RelationTypeOption {
  key: string;
  label: string;
  description: string;
}

/**
 * Story 1.17 v2.4 — D1-1 决策 C 混合 7 类（项目 Story 6-3 5 类 + 社区 prerequisite + example_of）
 * 用户在 Cmd+Shift+D 派生新节点时通过 Modal 选择本组中的一类作为新节点和源笔记的关系。
 * 7 类同时落到：
 *   1. 源笔记 callout `[!relation/<key>]+`（视觉提示）
 *   2. 新节点 frontmatter `relationships: [{type: <key>, target: [[源笔记]]}]`（机器可读）
 */
export const RELATION_TYPES: readonly RelationTypeOption[] = [
  {
    key: "prerequisite",
    label: "先修 (prerequisite)",
    description: "新节点是源笔记的先修知识（学源笔记必须先懂新节点）",
  },
  {
    key: "depends_on",
    label: "依赖 (depends_on)",
    description: "新节点在概念上依赖源笔记（理解新节点需要源笔记的概念）",
  },
  {
    key: "refines",
    label: "细化 (refines)",
    description: "新节点是源笔记某段的更细化版本",
  },
  {
    key: "extends",
    label: "扩展 (extends)",
    description: "新节点在源笔记基础上延伸或补全",
  },
  {
    key: "example_of",
    label: "例子 (example_of)",
    description: "新节点是源笔记某概念的具体例子或实例",
  },
  {
    key: "contradicts",
    label: "反驳 (contradicts)",
    description: "新节点与源笔记观点矛盾或反驳",
  },
  {
    key: "related_to",
    label: "相关 (related_to)",
    description: "一般性关联（兜底，不确定哪类时选这个）",
  },
] as const;

export function getRelationLabel(key: string): string {
  return RELATION_TYPES.find((r) => r.key === key)?.label ?? key;
}

export function isValidRelationKey(key: string): boolean {
  return RELATION_TYPES.some((r) => r.key === key);
}

/**
 * Story 1.17 v2.5 — D1-4 决策 B 可选 + D1-5 决策 C 三处都写
 * 用户在选完关系类型后弹第二个 modal，自由文本描述"为什么要派生这个节点"。
 * 留空 / Esc → description = "" (下游处理时跳过 callout body 行 + 跳过 frontmatter 字段 + 不注入 prompt)
 * 非空 → 写入 (1) 源笔记 callout body / (2) 新节点 frontmatter relationships[].description / (3) AI prompt
 */
export function buildAIDocPrompt(
  selected: string,
  sourcePath: string,
  activeBoard?: string,
  relationType?: string,
  description?: string,
): string {
  const activeBoardLine = activeBoard
    ? `活动白板: ${activeBoard}\n`
    : `活动白板: (Skill 会从 .canvas-config.yaml 或 AskUserQuestion 确定)\n`;

  const relationKey =
    relationType && isValidRelationKey(relationType)
      ? relationType
      : "related_to";
  const relationLabel = getRelationLabel(relationKey);
  const relationLine = `关系类型: ${relationKey} (${relationLabel})\n`;

  const trimmedDesc = (description ?? "").trim();
  const descLine = trimmedDesc
    ? `派生描述: ${trimmedDesc}\n`
    : `派生描述: (用户留空)\n`;

  return (
    `/ai-linked-doc\n` +
    `Please invoke the Skill tool with skill_name="ai-linked-doc" to handle this request.\n` +
    `Do NOT answer freely — follow the 8-step Skill flow strictly.\n` +
    `\n` +
    `选中文本:\n${selected}\n\n` +
    `源笔记路径: ${sourcePath}\n` +
    activeBoardLine +
    relationLine +
    descLine +
    `\n` +
    `请为这段内容派生一个新概念节点（扁平架构：节点/<concept>.md + 更新 原白板/<active_board>.md 的 ## Concepts）。`
  );
}

export function isBoardsPath(sourcePath: string): boolean {
  return sourcePath !== "unknown" && sourcePath.startsWith("原白板/");
}

export function isNodesPath(sourcePath: string): boolean {
  return sourcePath !== "unknown" && sourcePath.startsWith("节点/");
}

export function isFlatArchPath(sourcePath: string): boolean {
  return isBoardsPath(sourcePath) || isNodesPath(sourcePath);
}

export function extractBoardNameFromPath(sourcePath: string): string | null {
  if (!isBoardsPath(sourcePath)) return null;
  const filename = sourcePath.substring("原白板/".length);
  return filename.endsWith(".md")
    ? filename.substring(0, filename.length - 3)
    : filename;
}

/**
 * Story 1.17 v2.6 — 节点派生节点继承源节点的 source_board 白板归属。
 *
 * source_board frontmatter 实际格式（v4 Skill 写入）："[[原白板/<board_name>]]"。
 * Obsidian metadataCache 把 frontmatter 中的 wikilink 解析为：
 *   - 较新版本: Link-like 对象 `{ link: "原白板/<board>", path?: ... }`
 *   - 较老版本: 原始字符串 "[[原白板/<board>]]"
 *
 * 本函数对两种形态都 robust：先取出底层字符串，用 regex 提取 board name。
 * 失败 / 不在 `原白板/` 下 → null（让上层 fallback 到 .canvas-config.yaml 或 AskUserQuestion）。
 */
export function extractSourceBoardFromFrontmatter(
  frontmatter: Record<string, unknown> | undefined,
): string | null {
  if (!frontmatter) return null;
  const raw = frontmatter.source_board;
  if (!raw) return null;
  let str = "";
  if (typeof raw === "string") {
    str = raw;
  } else if (typeof raw === "object" && raw !== null) {
    const linkLike = raw as { link?: unknown; path?: unknown; display?: unknown };
    str =
      (typeof linkLike.link === "string" && linkLike.link) ||
      (typeof linkLike.path === "string" && linkLike.path) ||
      (typeof linkLike.display === "string" && linkLike.display) ||
      "";
  }
  if (!str) return null;
  const match = str.match(/(?:\[\[)?原白板\/([^\]|]+?)(?:\.md)?(?:\|[^\]]*)?(?:\]\])?$/);
  if (!match) return null;
  const board = match[1].trim();
  return board || null;
}

/**
 * Story 1.19 v4.0 — configure-whiteboard 全 plugin 化
 *
 * 把 Skill v3.1 的 7 步流程全部迁回 plugin script，零 LLM 调用：
 *   Step 1: 读 vault 级 .canvas-config.yaml subject（plugin: vault.adapter.read）
 *   Step 2: 场景判定 A/B（plugin: 路径检查）
 *   Step 3: 用户输入 board_name（plugin: input modal）
 *   Step 4.1: 文件级冲突（plugin: vault.getAbstractFileByPath）
 *   Step 4.2: 反向引用检测（plugin: metadataCache.resolvedLinks，10ms vs Skill 500ms）
 *   Step 5: 建白板 md（plugin: vault.create + processFrontMatter）
 *   Step 6: 种子笔记归类 move/copy（plugin: vault.rename / vault.copy）
 *   Step 7: 回执 Notice（plugin: new Notice）
 *
 * 收益：15-30s LLM 推理 → <300ms 全脚本完成。
 * Skill `configure-whiteboard` v3.1 保留作 fallback（用户手动调 /configure-whiteboard 仍能跑）。
 */

const ILLEGAL_BOARD_NAME_CHARS = /[\\/:*?"<>|#^[\]]/g;

/**
 * 清洗用户输入的白板名（去非法字符 + trim）。
 */
export function sanitizeBoardName(input: string): string {
  return input.replace(ILLEGAL_BOARD_NAME_CHARS, "").trim();
}

export function validateBoardName(name: string): {
  valid: boolean;
  reason?: string;
} {
  if (!name) return { valid: false, reason: "白板名不能为空" };
  if (name.length > 80)
    return { valid: false, reason: "白板名超过 80 字符" };
  if (ILLEGAL_BOARD_NAME_CHARS.test(name))
    return {
      valid: false,
      reason: `白板名含非法字符（${ILLEGAL_BOARD_NAME_CHARS.source}）`,
    };
  return { valid: true };
}

/**
 * Vault config schema（.canvas-config.yaml）。
 */
export interface VaultConfig {
  subject: string;
  subject_display?: string;
  active_board?: string | null;
  schema_version?: string;
}

/**
 * 极简 YAML 行解析（仅 key: value，不支持嵌套 / 数组）— 已知 .canvas-config.yaml 是平铺格式。
 *
 * 注意：实际 YAML 可能含注释（#）、引号包围的值。简化处理：取第一个 : 后内容，
 *   trim + 去外围引号。如果结构变复杂应换 yaml lib。
 */
export function parseVaultConfigYaml(text: string): VaultConfig | null {
  const lines = text.split(/\r?\n/);
  const out: Record<string, string | null> = {};
  for (const raw of lines) {
    const line = raw.replace(/^\s+|\s+$/g, "");
    if (!line || line.startsWith("#") || line.startsWith("---")) continue;
    if (line.startsWith("deprecated_paths:")) break;
    const colonIdx = line.indexOf(":");
    if (colonIdx <= 0) continue;
    const key = line.substring(0, colonIdx).trim();
    let value = line.substring(colonIdx + 1).trim();
    const hashIdx = value.indexOf("#");
    if (hashIdx >= 0) value = value.substring(0, hashIdx).trim();
    value = value.replace(/^["']|["']$/g, "");
    if (!value || value === "null") {
      out[key] = null;
    } else {
      out[key] = value;
    }
  }
  if (!out.subject) return null;
  return {
    subject: out.subject,
    subject_display: out.subject_display ?? undefined,
    active_board: out.active_board ?? null,
    schema_version: out.schema_version ?? undefined,
  };
}

/**
 * 反向引用检测：从 metadataCache.resolvedLinks 反查所有 wikilink 指向 sourceFile 的源 md。
 *
 * resolvedLinks 数据结构（Obsidian 1.5+）：
 *   { "源文件路径": { "目标文件路径": 出现次数, ... }, ... }
 *
 * 我们要找：所有 sourceMd（源 md），其 resolvedLinks[sourceMd][sourceFile.path] > 0。
 * 性能：200 笔记 < 10ms（一次性遍历 + 哈希查询）。
 */
export interface BacklinkHit {
  sourceMdPath: string;
  occurrences: number;
}

export function findBacklinkingNotes(
  resolvedLinks: Record<string, Record<string, number>>,
  targetPath: string,
): BacklinkHit[] {
  const hits: BacklinkHit[] = [];
  for (const [sourceMd, targets] of Object.entries(resolvedLinks)) {
    if (sourceMd === targetPath) continue;
    const count = targets[targetPath];
    if (typeof count === "number" && count > 0) {
      hits.push({ sourceMdPath: sourceMd, occurrences: count });
    }
  }
  return hits;
}

/**
 * 从节点 md 的 frontmatter 提取 source_board name（已在 ai-linked-doc.ts 实现，此处复用语义）。
 *
 * 期望格式 `"[[原白板/<board>]]"` → 返回 board name。
 * 不在 `原白板/` 下 → null（拒绝错位归属）。
 */
export function extractBoardFromBacklinkSource(
  frontmatter: Record<string, unknown> | undefined,
): string | null {
  if (!frontmatter) return null;
  const raw = frontmatter.source_board;
  if (!raw) return null;
  let str = "";
  if (typeof raw === "string") {
    str = raw;
  } else if (typeof raw === "object" && raw !== null) {
    const linkLike = raw as { link?: unknown; path?: unknown };
    str =
      (typeof linkLike.link === "string" && linkLike.link) ||
      (typeof linkLike.path === "string" && linkLike.path) ||
      "";
  }
  if (!str) return null;
  const match = str.match(
    /(?:\[\[)?原白板\/([^\]|]+?)(?:\.md)?(?:\|[^\]]*)?(?:\]\])?$/,
  );
  if (!match) return null;
  const board = match[1].trim();
  return board || null;
}

/**
 * 白板 md 模板（内嵌，避免运行时读取外部 templates/whiteboard.md.template 文件）。
 *
 * 模板与 .claude/skills/configure-whiteboard/templates/whiteboard.md.template v2.7 保持一致：
 *   - frontmatter (5 字段)
 *   - # 标题
 *   - 说明 callout
 *   - ## Concepts
 *   - ## 🔗 节点关系图（含 dataviewjs mermaid 自动生成块）
 *   - ## Recent Activity
 *
 * 占位符：{{board_name}} / {{created_at}}
 */
export const WHITEBOARD_TEMPLATE = `---
type: whiteboard
board_name: "{{board_name}}"
created_at: "{{created_at}}"
doc_count: 0
doc_mastery_avg: 0.00
---

# {{board_name}}

> [!info]+ 原白板说明（扁平架构 · round-11）
> 这是学习主题"**{{board_name}}**"的原白板。本文档即白板本身（不是白板目录的索引）。
>
> - **节点 md** 都在 vault 根的 \`节点/\` 文件夹（扁平池，一 vault 一学科零重名）
> - **subject** 字段读 vault 级 \`.canvas-config.yaml\`（不在每个 md frontmatter 重复）
> - 左栏文件树默认**折叠节点文件夹**，你主要从这份白板 md 入口管理
> - Cmd+Click \`[[wikilink]]\` 仍可跳转到节点 md（节点级 AI 对话继续工作）
>
> ## 你在这白板里能做什么
> - 选中任意文本 → \`Cmd+Shift+D\` 让 AI 派生新节点（Story 1.17），**自动建双向 wikilink**
> - 选中文本 → \`Cmd+Shift+A\` 加 Tips/错误/提问/关键点 callout + 3 态理解度 checkbox
> - 按 \`Cmd+G\` 打开 Graph View 看本白板所有 wikilink 拓扑
> - 按 \`Cmd+E\` 切 Reading View 看渲染后 callout

## Concepts

<!--
本 section 由三处维护：
  1. canvas:configure-whiteboard 命令（Story 1.19 v4 plugin）— 种子笔记 append 时写 "seed note (mastery: 0.30)"
  2. canvas:ai-linked-doc 命令（Story 1.17 v3 plugin hybrid）— AI 派生新节点时 append "extracted, weak (0.30)"
  3. 你手动 — 直接写 \`- [[xxx]]\` 都会被 Graph View 识别
wikilink 目标都指向 vault 根的 节点/ 文件夹下 md。
-->

## 🔗 节点关系图（v2.7 · 白板核心 · 自动从真实双链生成）

\`\`\`dataviewjs
const here = dv.current().file.link;
const nodes = dv.pages('"节点"')
  .where(p => p.source_board?.path === here.path);

if (nodes.length === 0) {
  dv.paragraph("> 🌱 当前白板暂无派生节点，用 Cmd+Shift+D 派生第一个");
} else {
  let chart = "graph TD\\n";
  const declared = new Set();
  nodes.forEach(n => {
    const id = n.file.name.replace(/[^a-zA-Z0-9_]/g, "_");
    if (!declared.has(id)) {
      const mastery = n.mastery_score ?? '—';
      chart += \`  \${id}["\${n.file.name}<br/>精通度 \${mastery}"]\\n\`;
      chart += \`  style \${id} fill:#fff3e0,stroke:#f57c00\\n\`;
      declared.add(id);
    }
    if (n["derived-from"]) {
      const srcName = n["derived-from"].fileName ? n["derived-from"].fileName() : n["derived-from"].path.split('/').pop().replace('.md','');
      const srcId = srcName.replace(/[^a-zA-Z0-9_]/g, "_");
      if (!declared.has(srcId)) {
        chart += \`  \${srcId}["\${srcName}<br/>(源笔记)"]\\n\`;
        chart += \`  style \${srcId} fill:#e1f5ff,stroke:#0288d1\\n\`;
        declared.add(srcId);
      }
    }
  });
  nodes.forEach(n => {
    if (n["derived-from"]) {
      const srcName = n["derived-from"].fileName ? n["derived-from"].fileName() : n["derived-from"].path.split('/').pop().replace('.md','');
      const src = srcName.replace(/[^a-zA-Z0-9_]/g, "_");
      const dst = n.file.name.replace(/[^a-zA-Z0-9_]/g, "_");
      chart += \`  \${src} -->|派生| \${dst}\\n\`;
    }
    (n.file.outlinks || []).forEach(link => {
      const target = nodes.find(p => p.file.path === link.path);
      if (target && target.file.name !== n.file.name) {
        const src = n.file.name.replace(/[^a-zA-Z0-9_]/g, "_");
        const dst = target.file.name.replace(/[^a-zA-Z0-9_]/g, "_");
        chart += \`  \${src} -.->|wikilink| \${dst}\\n\`;
      }
    });
  });
  dv.paragraph("\\\`\\\`\\\`mermaid\\n" + chart + "\\\`\\\`\\\`");
}
\`\`\`

> **白板 = 节点关系**（社区共识：Karpathy / Andy Matuschak / Nick Milo / Wikipedia / Maggie Appleton + 5 真实成熟项目均零分类容器段）。Cmd+G 看 Graph View 全 vault 拓扑。

## Recent Activity

- {{created_at}}: Whiteboard created
`;

export function renderWhiteboardTemplate(
  boardName: string,
  createdAt: string,
): string {
  return WHITEBOARD_TEMPLATE.replace(/\{\{board_name\}\}/g, boardName).replace(
    /\{\{created_at\}\}/g,
    createdAt,
  );
}

/**
 * 种子笔记 append 到白板 ## Concepts 的行格式（区别于 ai-linked-doc 的派生节点行）。
 */
export function buildSeedConceptsLine(seedStem: string): string {
  return `- [[节点/${seedStem}]] — seed note (mastery: 0.30)`;
}

export function buildSeedActivityLine(
  seedBasename: string,
  isoTimestamp: string,
): string {
  return `- ${isoTimestamp}: Seed note ${seedBasename} imported`;
}

/**
 * Story 1.19 v4.2 — 实时数白板 ## Concepts 段含 wikilink 的行数。
 *
 * 修复 doc_count 漂移 bug：v4.0/v4.1 plugin 每次派生 doc_count++，但用户手动删
 *   ## Concepts 行 / cleanup 时不会 --，导致 doc_count = 5 但实际只 3 行。
 * 修复方案：plugin 每次更新白板时**实时数**（不依赖累加），保证 frontmatter 准确。
 *
 * 数法：## Concepts section（直到下一个 ## 标题或 --- 分隔线）内行首是 `- [[` 的行。
 */
export function recountBoardConcepts(boardContent: string): number {
  const lines = boardContent.split(/\r?\n/);
  let inSection = false;
  let count = 0;
  for (const line of lines) {
    if (line.startsWith("## Concepts")) {
      inSection = true;
      continue;
    }
    if (!inSection) continue;
    if (line.startsWith("## ") || line.startsWith("---")) {
      break;
    }
    if (/^\s*- \[\[/.test(line)) {
      count++;
    }
  }
  return count;
}

/**
 * 节点池重名解析（同 ai-linked-doc / node-derivation 的语义，但接受任意 stem）。
 */
export function resolveUniqueSeedName(
  desiredStem: string,
  existsCheck: (path: string) => boolean,
): string {
  if (!existsCheck(`节点/${desiredStem}.md`)) return desiredStem;
  for (let n = 2; n <= 9; n++) {
    if (!existsCheck(`节点/${desiredStem}_${n}.md`)) {
      return `${desiredStem}_${n}`;
    }
  }
  throw new Error(
    `节点池 9+ 重名（${desiredStem}），可能概念拆分有问题，请手动改名`,
  );
}

/**
 * 场景判定：A 从零建（无 source 或 source 已在 原白板/ 下）/ B 从已有 md 派生。
 */
export type ConfigureScenario = "scenario_a" | "scenario_b";

export function determineScenario(
  sourcePath: string | null,
): ConfigureScenario {
  if (!sourcePath) return "scenario_a";
  if (sourcePath.startsWith("原白板/")) return "scenario_a";
  return "scenario_b";
}

/**
 * 反向引用结果聚合：把 BacklinkHit[] 升级为含 source_board 信息的结果。
 *
 * 给出每个反向引用节点的 source_board，用于 modal 列出"已属于哪个白板"。
 */
export interface BacklinkSummary {
  sourceMdPath: string;
  sourceBoardName: string | null;
}

export function summarizeBacklinks(
  hits: BacklinkHit[],
  getFrontmatter: (
    path: string,
  ) => Record<string, unknown> | undefined,
): BacklinkSummary[] {
  return hits.map((hit) => ({
    sourceMdPath: hit.sourceMdPath,
    sourceBoardName: extractBoardFromBacklinkSource(
      getFrontmatter(hit.sourceMdPath),
    ),
  }));
}

/**
 * 从 BacklinkSummary[] 提取去重的已存在白板列表（按出现频次排序）。
 */
export function deduplicateExistingBoards(
  summaries: BacklinkSummary[],
): string[] {
  const counter = new Map<string, number>();
  for (const s of summaries) {
    if (s.sourceBoardName) {
      counter.set(s.sourceBoardName, (counter.get(s.sourceBoardName) ?? 0) + 1);
    }
  }
  return Array.from(counter.entries())
    .sort((a, b) => b[1] - a[1])
    .map((e) => e[0]);
}
